              <div style={{ display:"flex", gap:8, marginTop:12, flexWrap:"wrap" }}>
                <span className="chip">🌿 Eco Green International</span>
                <span className="chip">👨‍💻 Intern Trainee</span>
              </div>
            </div>
          </div>
